import asyncio
from datetime import datetime, timezone, timedelta
from dataclasses import dataclass, field

@dataclass
class StatusPageCadence:
    severity: str
    declared_at: datetime
    comms_liaison_slack_id: str
    channel_id: str
    last_posted: datetime = field(default=None)

    @property
    def interval_minutes(self) -> int:
        return 30 if self.severity == "SEV1" else 60

    @property
    def first_deadline(self) -> datetime:
        return self.declared_at + timedelta(minutes=self.interval_minutes)

    def is_update_due(self, now: datetime) -> bool:
        if self.last_posted is None:
            return now >= self.first_deadline
        return (now - self.last_posted).seconds >= self.interval_minutes * 60

    def next_update_due_at(self, now: datetime) -> datetime:
        if self.last_posted is None:
            return self.first_deadline
        return self.last_posted + timedelta(minutes=self.interval_minutes)

async def run_cadence_watcher(
    cadence: StatusPageCadence,
    slack_client,
    warning_minutes_before: int = 5,
) -> None:
    """Remind comms liaison before the update window closes."""
    while True:
        await asyncio.sleep(60)
        now = datetime.now(timezone.utc)
        due_at = cadence.next_update_due_at(now)
        minutes_until_due = (due_at - now).seconds // 60

        if minutes_until_due <= warning_minutes_before and not cadence.is_update_due(now):
            await slack_client.chat_postMessage(
                channel=cadence.channel_id,
                text=(
                    f":bell: <@{cadence.comms_liaison_slack_id}> — "
                    f"status page update due in {minutes_until_due} minutes "
                    f"({due_at.strftime("%H:%M UTC")}). "
                    f"Post to statuspage.io now."
                ),
            )

        if cadence.is_update_due(now):
            # Post holding message automatically if liaison is unreachable
            await _post_holding_message_if_overdue(cadence, slack_client, now)

def update_affected_components(
    client: StatusPageClient,
    incident_id: str,
    components: dict[str, ComponentStatus],
) -> None:
    """Update component statuses to reflect actual impact.

    Args:
        components: mapping of component_id -> status
    """
    # Statuspage API: PATCH /incidents/{id} with component statuses
    client.client.patch(
        f"/pages/{client.page_id}/incidents/{incident_id}",
        json={
            "incident": {
                "components": {
                    cid: status.value for cid, status in components.items()
                }
            }
        },
    ).raise_for_status()

# At declaration (SEV1 inference latency)
update_affected_components(statuspage, incident_id, {
    INFERENCE_API_COMPONENT_ID: ComponentStatus.PARTIAL_OUTAGE,
    RAG_COMPONENT_ID: ComponentStatus.DEGRADED,
})

# At resolution
update_affected_components(statuspage, incident_id, {
    INFERENCE_API_COMPONENT_ID: ComponentStatus.OPERATIONAL,
    RAG_COMPONENT_ID: ComponentStatus.OPERATIONAL,
})
